 {"id":"bd-mblr.7.7.2","title":"Leak budget policy and detectors","description":"Define leak budgets and implement detectors for growth trends and hard-threshold violations.","design":"Define leak budget policy and implement detectors that compare observed resource slopes and end state deltas against limits.","acceptance_criteria":"- Policy defines baseline windows, tolerance bands, and escalation categories.
- Detectors identify sustained growth patterns and distinguish warmup effects from real leaks.
- Integration tests verify detector outputs on synthetic traces containing known leak signatures.","notes":"Detector output should align with performance and soak reporting formats for unified triage.","status":"open","priority":1,"issue_type":"task","created_at":"2026-02-13T03:05:21.928186299Z","created_by":"ubuntu","updated_at":"2026-02-13T03:09:00.824412352Z","source_repo":".","compaction_level":0,"original_size":0,"dependencies":[{"issue_id":"bd-mblr.7.7.2","depends_on_id":"bd-mblr.7.7","type":"parent-child","created_at":"2026-02-13T03:05:21.928186299Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-mblr.7.7.2","depends_on_id":"bd-mblr.7.7.1","type":"blocks","created_at":"2026-02-13T03:05:58.193754738Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
 {"id":"bd-mblr.7.7.3","title":"CI leak gate and actionable diagnostics","description":"Enforce leak budgets in CI with clear diagnostics and artifact links for investigation.","design":"Add CI leak gates that fail appropriately and provide precise diagnostics linked to resource timelines and offending scenarios.","acceptance_criteria":"- CI gate blocks on leak budget violations with clear component and scenario attribution.
- Failure artifacts include telemetry timelines, detector reasoning, and suggested next investigations.
- E2e CI simulation covers pass, warn, fail, and intermittent violation patterns.","notes":"Allow temporary waivers only with owner and expiry metadata to prevent silent budget erosion.","status":"open","priority":1,"issue_type":"task","created_at":"2026-02-13T03:05:22.007490001Z","created_by":"ubuntu","updated_at":"2026-02-13T03:09:00.910547755Z","source_repo":".","compaction_level":0,"original_size":0,"dependencies":[{"issue_id":"bd-mblr.7.7.3","depends_on_id":"bd-mblr.3.1.2","type":"blocks","created_at":"2026-02-13T03:05:58.345686775Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-mblr.7.7.3","depends_on_id":"bd-mblr.7.7","type":"parent-child","created_at":"2026-02-13T03:05:22.007490001Z","created_by":"ubuntu","metadata":"{}","thread_id":""},{"issue_id":"bd-mblr.7.7.3","depends_on_id":"bd-mblr.7.7.2","type":"blocks","created_at":"2026-02-13T03:05:58.270476637Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
 {"id":"bd-mblr.7.8","title":"Determinism Watchdog Across Toolchains","description":"Detect and classify deterministic drift across compiler/toolchain/environment variants using fixed seed corpus and normalized comparators.","design":"Monitor determinism across toolchain and environment permutations to detect behavior drift that can hide correctness bugs.","acceptance_criteria":"- Determinism matrix includes compiler versions, optimization profiles, and relevant runtime toggles.
- Runner compares semantic outputs and critical internal traces across matrix cells.
- Drift triage workflow classifies expected variance versus suspicious divergence with reproducible evidence.","notes":"Treat unexpected nondeterminism as reliability risk even when tests still pass.","status":"open","priority":1,"issue_type":"task","created_at":"2026-02-13T03:05:22.087248034Z","created_by":"ubuntu","updated_at":"2026-02-13T03:09:00.995934205Z","source_repo":".","compaction_level":0,"original_size":0,"dependencies":[{"issue_id":"bd-mblr.7.8","depends_on_id":"bd-mblr.7","type":"parent-child","created_at":"2026-02-13T03:05:22.087248034Z","created_by":"ubuntu","metadata":"{}","thread_id":""}]}
